// NewDB creates and validates a database connection.
func NewDB(dsn string) *DB {
	db, err := sql.Open("postgres", dsn)
	if err != nil {
		panic(fmt.Sprintf("NewDB: failed to open: %v", err))
	}
	if err := db.Ping(); err != nil {
		panic(fmt.Sprintf("NewDB: failed to ping: %v", err))
	}
	return &DB{db: db}
}
